function ModelMagicPot:MagicPotInfoResp(pb)
    local info = pb.info
    self.potNum = info.potNum
    self.phaseReward = {}
    self.rewardLvl = #info.phaseReward
    for _, v in ipairs(info.phaseReward) do
        self.phaseReward[v] = true
    end
    self.level = info.level

    FireEvent("MagicPotInfoResp")
    FireEvent("magicPotRedPointChange")
end

