function ModelMagicPot:GetTopShowItem()
    if not self.topShowItem then
        self.topShowItem = {}
        local cfg = GameTable.MagicGetConfigRef.magicGetShowItem
        local data = string.split(cfg, "|")
        for _, v in ipairs(data) do
            local t = {
                itemId = tonumber(v),
                itemType = 1
            }
            table.insert(self.topShowItem, t)
        end
    end
    return self.topShowItem
end

function ModelMagicPot:GetNextLvlReward()
    local refId = self.rewardLvl + 1
    local cfg = GameTable.MagicGetFloorRef[refId]
    local stage = 0
    local potNum = self.potNum or 0
    if cfg then
        stage = cfg.floor - math.floor(potNum / self.onePotNum)
    end
    return cfg, stage
end

function ModelMagicPot:GetRewardList()
    if not self.rewardList then
        local list = {}
        for _, v in pairs(GameTable.MagicGetFloorRef) do
            local data = {
                refId = v.refId,
                reward = LxDataHelper.ParseItem(v.reward),
                floor = v.floor
            }
            table.insert(list, data)
        end
        table.sort(list, function(a, b)
            return a.refId < b.refId
        end)
        self.rewardList = list
    end
    return self.rewardList
end

function ModelMagicPot:GetPotNum()
    return self.potNum or 0
end

function ModelMagicPot:GetPhaseReward()
    return self.phaseReward or {}
end

function ModelMagicPot:GetRewardPoolById(id)
    local list = {}
    for _, v in pairs(GameTable.MagicGetRewardRef) do
        if v.type == id and v.show ~= 1 then --and v.show ~= 1
            table.insert(list, v)
        end
    end
    return list
end

function ModelMagicPot:GetLookData()
    if not self.lookData then
        self.lookData = {}
        local cfg = GameTable.MagicGetRewardLvRef
        for i, v in ipairs(cfg) do
            local mustRewards = LxDataHelper.ParseItem(v.reward)
            local strInfo = string.split(v.weight, ",")
            local rewards = {}
            for _, v2 in ipairs(strInfo) do
                local id = tonumber(string.split(v2, "=")[1])
                local list =  self:GetRewardPoolById(id)
                table.sort(list, function(a, b)
                    return a.refId < b.refId
                end)
                for _, v3 in ipairs(list) do
                    local item = LxDataHelper.ParseItem_4(v3.reward)
                    table.insert(rewards, item)
                end
            end
            local data = {
                startNum = v.num,
                endNum = cfg[i + 1] ~= nil and cfg[i + 1].num - 1 or 0,
                mustRewards = mustRewards,
                rewards = rewards
            }
            table.insert(self.lookData, data)
        end
    end
    return self.lookData
end

