function ModelMagicPot:GetGiftRedPoint()
	local list = gModelShop:GetShopRefByShopType(21) or {}
    for _, v in ipairs(list) do
        if Vector2.buyType == ModelPopupGift.BUYTYPE_FREE or (v.buyType == ModelPopupGift.BUYTYPE_JEWEL and v.item.itemNum == 0) then
            local shopItemData = gModelShop:GetShopItemNetData(1010, v.refId)
            if shopItemData then
                local buyNum = shopItemData:GetHasBuyNum()
                return buyNum < v.limitCount.itemNum
            end
        end
    end
    return false
end

function ModelMagicPot:GetRewardRedpoint()
    local potNum = self:GetPotNum()
    local num = math.floor(potNum / self.onePotNum)
    for _, v in ipairs(GameTable.MagicGetFloorRef) do
        if num >= v.floor and not self.phaseReward[v.refId] then
            return true, v
        end
    end
    return false
end

function ModelMagicPot:GetShowRewardBtn()
    for _, v in ipairs(GameTable.MagicGetFloorRef) do
        if not self.phaseReward[v.refId] then
            return true
        end
    end
    return false
end

function ModelMagicPot:GetRankTime()
	local nowTime = GetTimestamp()
	local nowWeek = tonumber(os.date("%w", nowTime))
	local nowH = tonumber(os.date("%H", nowTime))
	local nowM = tonumber(os.date("%M", nowTime))
	local nowS = tonumber(os.date("%S", nowTime))
	local nowTick = (nowH * 60 * 60) + (nowM * 60) + nowS
	local endTick = 0
	if nowWeek < 1 then
		endTick = 86400 - nowTick
	else
		local day = 7 - nowWeek
		endTick = (day * 86400) + 86400 - nowTick
	end
	return math.ceil(endTick + nowTime)
end

function ModelMagicPot:GetPotRes()
    local potNum = self:GetPotNum()
    local pot = math.floor(potNum / self.onePotNum)
    local index = pot % 4
    return potRes[index]
end

return ModelMagicPot